.proj-details__tb-pagination[data-v-2be6c54a] {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 12px;
  padding-top: 14px;
}
.proj-details__tb-page-btn[data-v-2be6c54a] {
  padding: 5px 14px;
  border: 1px solid var(--color-border, #e5e7eb);
  border-radius: 6px;
  background: #fff;
  font-size: 13px;
  color: var(--color-text-primary, #1a1a2e);
  cursor: pointer;
  transition: background 0.15s, border-color 0.15s;
}
.proj-details__tb-page-btn[data-v-2be6c54a]:hover:not(:disabled) {
  background: #fafbfd;
  border-color: #4a90d9;
}
.proj-details__tb-page-btn[data-v-2be6c54a]:disabled {
  opacity: 0.4;
  cursor: default;
}
.proj-details__tb-page-info[data-v-2be6c54a] {
  font-size: 12px;
  color: var(--color-text-muted, #9ca3af);
}

/* ── Per-project Timeline KPI ── */
.proj-details__row--kpi[data-v-2be6c54a] {
  gap: 16px;
}
.proj-details__kpi-stat[data-v-2be6c54a] {
  background: var(--bg-card, #fff);
  border: 1px solid var(--color-border, #e5e7eb);
  border-radius: 10px;
  padding: 20px;
  display: flex;
  flex-direction: column;
  align-items: center;
  text-align: center;
}
.proj-details__kpi-stat-value[data-v-2be6c54a] {
  font-size: 28px;
  font-weight: 700;
  color: var(--color-text-primary, #1a1a2e);
  line-height: 1.2;
}
.proj-details__kpi-stat-label[data-v-2be6c54a] {
  font-size: 12px;
  font-weight: 600;
  color: var(--color-text-secondary, #6b7280);
  margin-top: 4px;
  text-transform: uppercase;
  letter-spacing: 0.3px;
}
.proj-details__kpi-stat-sub[data-v-2be6c54a] {
  font-size: 11px;
  color: var(--color-text-muted, #9ca3af);
  margin-top: 4px;
}
.proj-details__kpi-bar[data-v-2be6c54a] {
  width: 100%;
  max-width: 160px;
  height: 6px;
  background: #f1f5f9;
  border-radius: 3px;
  overflow: hidden;
  margin-top: 10px;
}
.proj-details__kpi-bar-fill[data-v-2be6c54a] {
  height: 100%;
  border-radius: 3px;
  transition: width 0.5s ease;
}
.proj-details__kpi-bar-fill--low[data-v-2be6c54a] {
  background: #ef4444;
}
.proj-details__kpi-bar-fill--mid[data-v-2be6c54a] {
  background: #f59e0b;
}
.proj-details__kpi-bar-fill--high[data-v-2be6c54a] {
  background: #10b981;
}

/* ── Responsive ── */
@media (max-width: 1024px) {
.proj-details__row--three[data-v-2be6c54a] {
    grid-template-columns: 1fr 1fr;
}
}
@media (max-width: 768px) {
.proj-details__row--two[data-v-2be6c54a],
  .proj-details__row--three[data-v-2be6c54a] {
    grid-template-columns: 1fr;
}
.proj-details__info-grid[data-v-2be6c54a] {
    grid-template-columns: 1fr;
}
}
